// Helper functions
func categoryBadgeClass(category string) string {
	switch category {
	case "code_review":
		return "badge-info"
	case "bug_fix":
		return "badge-error"
	case "feature":
		return "badge-success"
	case "refactor":
		return "badge-warning"
	case "testing":
		return "badge-secondary"
	default:
		return "badge-ghost"
	}
}

func favoriteClass(isFavorite bool) string {
	if isFavorite {
		return "text-warning"
	}
	return ""
}

